%[text] ### Multiple Plots
%[text] #### Scaled Squares
%[text] ![](text:image:9790)![](text:image:98db)
% Single Square: 원점 중심, 한변의 길이는 2

%%
% Scaled Squares: 축소된 10개의 정사각형

%%
%[text] ### Circles on a Circle
%[text] 반지름이 5인 원 위에 반지름이 1인 원들이 16개
%[text] ![](text:image:0d18)
% Draw a gray circle, r=5
a = linspace(0, 2*pi, 161)';
x = cos(a); y = sin(a);
plot(5*x, 5*y, 'Color',[0.5 0.5 0.5]);
axis equal; axis off; axis(6.1*[-1 1 -1 1]);
%%
% Draw the circles on the circle
%  원을 16등분한 점을 중심으로 원 그리기 

%%
%[text] ### Eyes
%[text] ![](text:image:7cec)
%[text] #### 왼쪽 쳐다보기
n = 100;
t = linspace(0, 2*pi, n)';
x = cos(t);
y = sin(t);
c = 1:5; % center
r = c;   % radius
X = x*r + c;
Y = y*r;
plot(X,Y, X-10,Y, 'LineWidth', 2) 
axis equal;
%%
%[text] #### 오른쪽 쳐다보기
% Look right
%%
%[text] #### 눈을 가운데로 모으기
% Look center
%%
%[text] #### 눈을 치켜뜨기
% Look up
%%
%[text] ### Function Plot
%[text] - `fplot()` 활용하기 \
fplot(@(x) x.^2+4*sin(2*x)-1, [-3 3], 'b-');
%%
%[text] - `fimplicit()` 활용하기 \
fimplicit(@(x,y) x.^2 - y.^2 - 1);
%%
%[text] 그래프 속성 변경하기
fp = fimplicit(@(x,y) y.*sin(x) + x.*cos(y) - 1);
fp.Color = 'r';
%%
%[text] ## Curves
%[text] List of Famous Curves
%[text] [https://www.matematica.pt/en/useful/list-curves.php](https://www.matematica.pt/en/useful/list-curves.php)
%%
%[text] ### Lituus Curves
%[text] $r^2 = \\frac{a^2}{\\theta}$
a = 2;
t = linspace(pi/4, 50*pi, 10000);
r = a./sqrt(t);
x = r .* cos(t);
y = r .* sin(t);
plot(x, y, 'r-');
axis equal;
%%
%[text] ### Astroid
%[text] $x^{2/3}+ y^{2/3} = a^{2/3$
a  = 2;
syms x y
fp = fimplicit((x^2)^(1/3) + (y^2)^(1/3) == 1, [-1 1]);
fp.Color = 'r';
axis equal;
%%
